#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

__global__ void jacobi_iteration(const float* f_old, float* f, float* error_array) {
    int idx_i = blockIdx.x * blockDim.x + threadIdx.x + 1;
    int idx_j = blockIdx.y * blockDim.y + threadIdx.y + 1;

    if (idx_i <= N-2 && idx_j <= N-2) {
        float t = 0.25f * (f_old[IDX(idx_i-1, idx_j)] +
                           f_old[IDX(idx_i+1, idx_j)] +
                           f_old[IDX(idx_i, idx_j-1)] +
                           f_old[IDX(idx_i, idx_j+1)]);
        float df = t - f_old[IDX(idx_i, idx_j)];
        f[IDX(idx_i, idx_j)] = t;
        error_array[IDX(idx_i, idx_j)] = df * df;
    }
}

__global__ void copy_inner(const float* f, float* f_old) {
    int idx_i = blockIdx.x * blockDim.x + threadIdx.x;
    int idx_j = blockIdx.y * blockDim.y + threadIdx.y;

    if (idx_i >= 1 && idx_i <= N-2 && idx_j >= 1 && idx_j <= N-2) {
        f_old[IDX(idx_i, idx_j)] = f[IDX(idx_i, idx_j)];
    }
}

void initialize_data(float* f) {
    for (int j = 0; j < N; ++j) {
        for (int i = 0; i < N; ++i) {
            if (i == 0 || i == N-1) {
                f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
            }
            else if (j == 0 || j == N-1) {
                f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
            }
            else {
                f[IDX(i,j)] = 0.0f;
            }
        }
    }
}

int main () {
    auto start_time = std::chrono::steady_clock::now();

    float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
    float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    initialize_data(f);
    initialize_data(f_old);

    float *d_f, *d_f_old, *d_error_array;
    cudaMalloc((void**)&d_f, N * N * sizeof(float));
    cudaMalloc((void**)&d_f_old, N * N * sizeof(float));
    cudaMalloc((void**)&d_error_array, N * N * sizeof(float));

    cudaMemcpy(d_f, f, N * N * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_f_old, f_old, N * N * sizeof(float), cudaMemcpyHostToDevice);

    const int max_iters = 10000;
    int num_iters = 0;

    dim3 blockDim(16,16);
    dim3 gridDim((N+blockDim.x-1)/blockDim.x, (N+blockDim.y-1)/blockDim.y);

    auto start = std::chrono::steady_clock::now();

    while (error > tolerance && num_iters < max_iters) {
        // Initialize error array to 0 on device
        cudaMemset(d_error_array, 0, N * N * sizeof(float));

        jacobi_iteration<<<dim3((N-2+15)/16,(N-2+15)/16), dim3(16,16)>>>(d_f_old, d_f, d_error_array);
        cudaDeviceSynchronize();

        copy_inner<<<gridDim, blockDim>>>(d_f, d_f_old);
        cudaDeviceSynchronize();

        // Copy error array back to host to reduce
        float* h_error_array = (float*)malloc(N * N * sizeof(float));
        cudaMemcpy(h_error_array, d_error_array, N * N * sizeof(float), cudaMemcpyDeviceToHost);

        double error_sum = 0.0;
        for (int i = 0; i < N*N; i++) {
            error_sum += h_error_array[i];
        }
        free(h_error_array);

        error = sqrtf(static_cast<float>(error_sum) / (N * N));

        if (num_iters % 1000 == 0) {
            std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
        }

        ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    cudaMemcpy(f, d_f, N * N * sizeof(float), cudaMemcpyDeviceToHost);

    if (error <= tolerance && num_iters < max_iters) {
        std::cout << "PASS" << std::endl;
    }
    else {
        std::cout << "FAIL" << std::endl;
        cudaFree(d_f);
        cudaFree(d_f_old);
        cudaFree(d_error_array);
        free(f);
        free(f_old);
        return -1;
    }

    cudaFree(d_f);
    cudaFree(d_f_old);
    cudaFree(d_error_array);
    free(f);
    free(f_old);

    auto end_time = std::chrono::steady_clock::now();
    auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
    double duration = total_time * 1e-9;
    std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

    return 0;
}
